// Parse voicemail retry leads from Supabase REST query
// Fresh cold calls come from the sales sequence engine via webhook.
// This path handles ONLY voicemail retries from the scheduled trigger.

const EXCLUDED_STATUSES = ['converted', 'unsubscribed', 'rejected', 'paying', 'demo_booked', 'churned'];

const result = $input.first().json;

// Handle array result from REST API
if (Array.isArray(result) && result.length > 0) {
  const filtered = result.filter(lead => !EXCLUDED_STATUSES.includes(lead.status) && lead.phone);
  if (filtered.length === 0) return [{ json: { _empty: true, reason: 'No eligible voicemail retry leads today' } }];
  return filtered.map(lead => ({ json: { ...lead, _call_source: 'voicemail_retry' } }));
}

// Handle single object result
if (result && !result.error && result.id) {
  if (EXCLUDED_STATUSES.includes(result.status) || !result.phone) {
    return [{ json: { _empty: true, reason: 'Lead excluded or has no phone' } }];
  }
  return [{ json: { ...result, _call_source: 'voicemail_retry' } }];
}

return [{ json: { _empty: true, reason: 'No voicemail retry leads due today' } }];

// TCPA Compliance Gate - runs before EVERY call attempt
// Checks: phone exists, not DNC, business hours in lead's timezone, not rejected/unsubscribed

const lead = $input.first().json;
const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;

// --- Check 1: Phone number exists ---
if (!lead.phone) {
  return [{ json: { ...lead, _tcpa_blocked: true, _tcpa_reason: 'No phone number on lead' } }];
}

// --- Check 2: DNC flag ---
let dncChecked = lead.dnc_checked || false;
let currentStatus = lead.status || '';

// Re-fetch from DB to get latest DNC + status
try {
  const emailParam = encodeURIComponent(lead.email);
  const resp = await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?email=eq.${emailParam}&select=dnc_checked,status`,
    {
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`
      }
    }
  );
  const rows = await resp.json();
  if (rows && rows[0]) {
    dncChecked = rows[0].dnc_checked || false;
    currentStatus = rows[0].status || currentStatus;
  }
} catch (e) {
  // Use lead's existing data if fetch fails
}

if (dncChecked === true) {
  return [{ json: { ...lead, _tcpa_blocked: true, _tcpa_reason: 'TCPA: Lead is on DNC list (dnc_checked=true)' } }];
}

// --- Check 3: Lead status not rejected/unsubscribed ---
if (['rejected', 'unsubscribed'].includes(currentStatus)) {
  return [{ json: { ...lead, _tcpa_blocked: true, _tcpa_reason: 'TCPA: Lead status is ' + currentStatus + ' - do not call' } }];
}

// --- Check 4: Business hours (8 AM - 9 PM in lead's timezone) ---
const leadTimezone = lead.timezone || 'America/New_York';
try {
  const nowInLeadTz = new Date(new Date().toLocaleString('en-US', { timeZone: leadTimezone }));
  const hour = nowInLeadTz.getHours();
  if (hour < 8 || hour >= 21) {
    return [{ json: { ...lead, _tcpa_blocked: true, _tcpa_reason: `TCPA: Outside calling hours (${hour}:00 in ${leadTimezone}). Allowed: 8AM-9PM.` } }];
  }
} catch (e) {
  // Fallback: assume US Eastern
  const utcHour = new Date().getUTCHours();
  const estHour = (utcHour - 5 + 24) % 24;
  if (estHour < 8 || estHour >= 21) {
    return [{ json: { ...lead, _tcpa_blocked: true, _tcpa_reason: `TCPA: Outside calling hours (EST fallback: ${estHour}:00)` } }];
  }
}

// All checks passed
return [{ json: { ...lead, _tcpa_blocked: false, _tcpa_reason: 'All TCPA checks passed' } }];

// Look up the business's retell_agent_id from the businesses table
// Falls back to $env.RETELL_AGENT_ID for BayFlow (manually configured)

const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SUPABASE_ANON_KEY = $env.SUPABASE_SERVICE_KEY;

const lead = $input.first().json;
const businessId = lead.business_id || lead.businessId || '';

let retellAgentId = '';
let businessSiteUrl = '';
let businessCalUrl = 'https://cal.com/shalinp';
let businessDisplayName = lead.business_name || 'your business';

// Query the businesses table for this lead's business retell_agent_id
if (businessId) {
  try {
    const response = await fetch(
      `${SUPABASE_URL}/rest/v1/businesses?business_id=eq.${encodeURIComponent(businessId)}&select=retell_agent_id,name,site_url,cal_booking_url`,
      {
        headers: {
          'apikey': SUPABASE_ANON_KEY,
          'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
          'Content-Type': 'application/json'
        }
      }
    );
    const businesses = await response.json();
    if (businesses && businesses.length > 0) {
      const biz = businesses[0];
      if (biz.retell_agent_id) {
        retellAgentId = biz.retell_agent_id;
      }
      if (biz.name) {
        businessDisplayName = biz.name;
      }
      if (biz.site_url) {
        businessSiteUrl = biz.site_url;
      }
      if (biz.cal_booking_url) {
        businessCalUrl = biz.cal_booking_url;
      }
    }
  } catch (err) {
    // Silently fall back to env variable
  }
}

// Fallback: use global RETELL_AGENT_ID env var (for BayFlow or manually configured agents)
// Note: in n8n Code nodes, env vars are accessed via $env
// but we pass it through as a flag so the HTTP node can use {{ $env.RETELL_AGENT_ID }}
const useEnvFallback = !retellAgentId;

return [{
  json: {
    ...lead,
    _retell_agent_id: retellAgentId,
    _use_env_fallback: useEnvFallback,
    _business_site_url: businessSiteUrl,
    _business_cal_url: businessCalUrl,
    _business_display_name: businessDisplayName
  }
}];

// Parse trigger data from sales sequence engine or manual call
// The sales sequence engine sends full lead data including id, email, phone,
// first_name, last_name, business_name, business_id, touchType, touchNumber, source
const body = $input.first().json.body || $input.first().json;

const email = body.email || '';
const phone = body.phone || '';
const firstName = body.first_name || body.firstName || 'there';
const lastName = body.last_name || body.lastName || '';
const businessName = body.business_name || body.businessName || 'your shop';
const businessId = body.business_id || body.businessId || '';
const leadId = body.id || body.leadId || '';
const touchType = body.touchType || 'cold_call';
const touchNumber = body.touchNumber || 1;
const source = body.source || 'manual';

if (!phone || !email) {
  return [{ json: { _error: true, message: 'Missing required fields: email and phone' } }];
}

return [{
  json: {
    id: leadId,
    email,
    phone,
    first_name: firstName,
    last_name: lastName,
    business_name: businessName,
    business_id: businessId,
    touchType,
    touchNumber,
    _call_source: source
  }
}];

const payload = $input.first().json.body || $input.first().json;

// Retell webhook payload structure
const callId = payload.call_id || payload.call?.call_id || '';
const callStatus = payload.call_status || payload.call?.status || 'unknown';
const duration = payload.duration_ms || payload.call?.duration_ms || 0;
const transcript = payload.transcript || payload.call?.transcript || '';
const disconnectReason = payload.disconnect_reason || payload.call?.disconnect_reason || '';
const metadata = payload.metadata || payload.call?.metadata || {};

// Determine call outcome
let callOutcome = 'unknown';
let bookingMade = false;
let isVoicemail = false;
let notInterested = false;

// Check transcript for booking signals
const transcriptLower = (typeof transcript === 'string' ? transcript : JSON.stringify(transcript)).toLowerCase();

if (transcriptLower.includes('book') || transcriptLower.includes('schedule') || transcriptLower.includes('demo') || transcriptLower.includes('set up') || transcriptLower.includes('sounds good') || transcriptLower.includes('let\'s do it')) {
  callOutcome = 'interested_booking';
  bookingMade = true;
} else if (disconnectReason === 'voicemail_reached' || transcriptLower.includes('voicemail') || transcriptLower.includes('leave a message') || duration < 15000) {
  callOutcome = 'voicemail';
  isVoicemail = true;
} else if (transcriptLower.includes('not interested') || transcriptLower.includes('no thanks') || transcriptLower.includes('don\'t call') || transcriptLower.includes('remove me') || transcriptLower.includes('stop calling')) {
  callOutcome = 'not_interested';
  notInterested = true;
} else if (transcriptLower.includes('call back') || transcriptLower.includes('busy right now') || transcriptLower.includes('not a good time')) {
  callOutcome = 'callback_requested';
} else {
  callOutcome = 'completed_no_action';
}

return [{
  json: {
    call_id: callId,
    call_status: callStatus,
    call_outcome: callOutcome,
    duration_seconds: Math.round(duration / 1000),
    transcript: typeof transcript === 'string' ? transcript : JSON.stringify(transcript),
    disconnect_reason: disconnectReason,
    booking_made: bookingMade,
    is_voicemail: isVoicemail,
    not_interested: notInterested,
    lead_email: metadata.lead_email || '',
    business_name: metadata.business_name || '',
    first_name: metadata.first_name || '',
    booking_url: metadata.booking_url || 'https://cal.com/shalinp',
    business_id: metadata.business_id || '',
    raw_payload: payload
  }
}];

